import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useDispatch } from 'react-redux';
import { setCredentials } from '../store/authSlice';
import { authAPI } from '../services/api';

export default function Login() {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const [form, setForm] = useState({ email: '', password: '' });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      const res = await authAPI.login(form);
      dispatch(setCredentials({ user: res.data.user, token: res.data.token }));
      navigate('/dashboard');
    } catch (err) {
      setError(err.response?.data?.message || 'Login failed. Check your credentials.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="page-bg flex items-center justify-center px-4 min-h-screen">
      <div className="w-full max-w-sm animate-slide-up">
        {/* Logo */}
        <div className="text-center mb-8">
          <div className="w-14 h-14 rounded-2xl flex items-center justify-center mx-auto mb-4 text-2xl font-black text-white"
            style={{ background: 'linear-gradient(135deg, #7c3aed, #a855f7)' }}>
            HE
          </div>
          <h1 className="text-2xl font-bold text-white">Welcome back</h1>
          <p className="text-gray-400 text-sm mt-1">Sign in to your HireEasy account</p>
        </div>

        <div className="glass-card p-8">
          {error && (
            <div className="mb-5 p-3.5 rounded-xl bg-red-500/10 border border-red-500/30 text-red-300 text-sm">
              ⚠️ {error}
            </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="block text-xs text-gray-400 mb-1.5 font-medium">Email</label>
              <input
                type="email"
                required
                className="input-field"
                placeholder="you@example.com"
                value={form.email}
                onChange={(e) => setForm({ ...form, email: e.target.value })}
              />
            </div>
            <div>
              <label className="block text-xs text-gray-400 mb-1.5 font-medium">Password</label>
              <input
                type="password"
                required
                className="input-field"
                placeholder="••••••••"
                value={form.password}
                onChange={(e) => setForm({ ...form, password: e.target.value })}
              />
            </div>

            <button
              type="submit"
              disabled={loading}
              className="btn-primary w-full flex items-center justify-center gap-2 mt-2 disabled:opacity-50"
            >
              {loading ? (
                <><div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" /> Signing in...</>
              ) : '✨ Sign In'}
            </button>
          </form>

          <p className="text-center text-gray-500 text-sm mt-5">
            New here?{' '}
            <Link to="/register" className="text-purple-400 hover:text-purple-300 font-medium">Create an account</Link>
          </p>
        </div>

        {/* Features teaser */}
        <div className="mt-6 grid grid-cols-3 gap-3">
          {[
            { icon: '🌐', label: 'Real-time Jobs' },
            { icon: '📄', label: 'Resume Match' },
            { icon: '🏅', label: 'Scholarships' },
          ].map((f) => (
            <div key={f.label} className="glass-card p-3 text-center">
              <div className="text-xl mb-1">{f.icon}</div>
              <div className="text-gray-400 text-[10px]">{f.label}</div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
